using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public class DocumentSummaryService
{
    /// <summary>
    /// Produces an extractive summary by scoring sentences on word frequency
    /// and returning the top-ranked ones in their original order.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        var topIndices = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return text
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => s.Length > 0)
            .Select(s => s + ".")
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        var stopWords = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
            "have", "has", "had", "do", "does", "did", "will", "would", "shall",
            "should", "may", "might", "must", "can", "could", "and", "but", "or",
            "nor", "not", "so", "yet", "both", "either", "neither", "each", "every",
            "all", "any", "few", "more", "most", "other", "some", "such", "no",
            "of", "in", "to", "for", "with", "on", "at", "from", "by", "about",
            "as", "into", "through", "during", "before", "after", "above", "below",
            "between", "out", "off", "over", "under", "again", "further", "then",
            "once", "it", "its", "this", "that", "these", "those", "i", "me", "my",
            "we", "our", "you", "your", "he", "him", "his", "she", "her", "they", "them"
        };

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (word.Length <= 2 || stopWords.Contains(word))
                    continue;

                frequencies.TryGetValue(word, out var count);
                frequencies[word] = count + 1;
            }
        }

        return frequencies;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (var i = 0; i < sentences.Count; i++)
        {
            var words = GetWords(sentences[i]);
            if (words.Count == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => wordFrequencies[w]);

            // Normalize by sentence length to avoid bias toward long sentences
            scored.Add((i, score / words.Count));
        }

        return scored;
    }

    private static List<string> GetWords(string sentence)
    {
        return sentence
            .Split([' ', ',', ';', ':', '"', '\'', '(', ')', '[', ']', '{', '}', '\n', '\r', '\t'],
                StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(w => w.Trim('.', '!', '?').ToLowerInvariant())
            .Where(w => w.Length > 0)
            .ToList();
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly DocumentSummaryService _summaryService;

    public SummaryController(DocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

